handler: async () => {
  const current = await session.rpc.model.getCurrent().catch(() => ({ modelId: undefined }));
  const isLooping = detectLoopingBehavior();
  const turnsSinceLastSwitch = confusionMetrics.turnCount - confusionMetrics.lastSwitchTurn;

  // Compute a single actionable alert string for the most important confusion signal.
  let confusionAlert = "OK";
  if (isLooping && confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold) {
    confusionAlert = "HIGH: looping + consecutive errors — swap candidate";
  } else if (isLooping) {
    confusionAlert = "ELEVATED: looping detected";
  } else if (confusionMetrics.errorCount >= CONFUSION_THRESHOLDS.consecutiveErrorThreshold) {
    confusionAlert = "ELEVATED: consecutive errors";
  } else if (confusionMetrics.repeatedPatternCount >= CONFUSION_THRESHOLDS.repeatingPatternThreshold) {
    confusionAlert = "ELEVATED: repeated response patterns";
  }

  return JSON.stringify(
    {
      // Concise at-a-glance section for local debugging.
      snapshot: {
        activeModel: current.modelId || null,
        lastImplementationModel,
        confusion: {
          alert: confusionAlert,
          isLooping,
          errorCount: confusionMetrics.errorCount,
          repeatedPatternCount: confusionMetrics.repeatedPatternCount,
          turnsSinceLastSwitch,
        },
      },
      lastReviewModel,
      lastDecision,
      confusionMetrics: {
        turnCount: confusionMetrics.turnCount,
        recentMessageCount: confusionMetrics.recentMessages.length,
        errorCount: confusionMetrics.errorCount,
        repeatedPatternCount: confusionMetrics.repeatedPatternCount,
        turnsSinceLastConfusionSwitch: turnsSinceLastSwitch,
        isLooping,
      },
    },
    null,
    2,
  );
},

